/// Maps a kebab-case folder name to its module name, e.g. "merge-queue" -> "GitHubRestAPIMergeQueue".
func targetName(_ folderName: String) -> String {
    "GitHubRestAPI" + folderName.split(separator: "-")
        .map { $0.prefix(1).uppercased() + $0.dropFirst() }
        .joined()
}

let package = Package(
    name: "GitHubRestAPISwiftOpenAPI",
    platforms: [
        .macOS(.v10_15), .iOS(.v13), .tvOS(.v13), .watchOS(.v6), .visionOS(.v1),
    ],
    products: sourceFolders.map {
        .library(name: targetName($0), targets: [targetName($0)])
    },
    dependencies: [
        .package(url: "https://github.com/apple/swift-openapi-runtime", from: "1.0.0"),
        .package(url: "https://github.com/apple/swift-openapi-urlsession", from: "1.0.0"),
    ],
    targets: sourceFolders.map {
        .target(
            name: targetName($0),
            dependencies: [
                .product(name: "OpenAPIRuntime", package: "swift-openapi-runtime"),
                .product(name: "OpenAPIURLSession", package: "swift-openapi-urlsession"),
            ],
            path: "Sources/\($0)"
